with detail = 1 {
    with link = "line.nl.ZEH" {
        let ze = path("d1.nl.zeh");

        with railway = :first :double :cat:dc15 :pax {
            track(ze[:zaa.ye, :hoo.yh]);
            track(ze[:hoo.yh, :hoo.ym]);
            track(ze[:hoo.ym, :hke]);
            track(:single, ze[:hke, :enk] >> 0.5md << 0.5mt);
        }
    }

    with link = "line.nl.ZSG" {
        let zs = path("d1.nl.zsg");

        with railway = :first :double :cat:dc15 :pax {
            track(zs[:zaa, :asl.yr]);
            track(zs[:asl.yr, :sin.yz]);
        }
    }
}

